// In your React component:
// 1. On map load, fetch scores and add source:
map.on('load', async () => {
  const bbox = map.getBounds().toArray().flat().join(',');
  const resp = await fetch(`/parcels/scores?bbox=${bbox}`);
  const geojson = await resp.json();

  map.addSource('parcel-scores', { type: 'geojson', data: geojson });

  // Add the layers from mapbox_config.json
  map.addLayer({ /* parcel-scores-3d config */ });
  map.addLayer({ /* parcel-outlines config */ });
  map.addLayer({ /* parcel-score-labels config */ });
});

// 2. On map move, re-fetch for new viewport:
map.on('moveend', async () => {
  const bbox = map.getBounds().toArray().flat().join(',');
  const resp = await fetch(`/parcels/scores?bbox=${bbox}`);
  const geojson = await resp.json();
  map.getSource('parcel-scores').setData(geojson);
});

// 3. On parcel click, fetch explanation:
map.on('click', 'parcel-scores-3d', async (e) => {
  const parcelId = e.features[0].properties.parcel_id;
  const resp = await fetch(`/parcels/${parcelId}/explain`);
  const explanation = await resp.json();
  // Display in sidebar component
  setSidebarContent(explanation);
});
